/* button.module.css */
.base {
  padding: 0.5rem 1rem;
  border-radius: 4px;
  font-weight: 600;
}

.primary {
  composes: base;
  background: var(--color-brand);
  color: #fff;
}

/* Override a third-party tooltip globally */
:global(.tippy-box) {
  font-size: 0.75rem;
}

// Button.tsx
import styles from './button.module.css';
export const Button = () => <button className={styles.primary}>Submit</button>;

import { cva, type VariantProps } from 'class-variance-authority';
import styles from './Button.module.css';

const button = cva(styles.base, {
  variants: {
    size: { sm: styles.sm, md: styles.md, lg: styles.lg },
    intent: { primary: styles.primary, danger: styles.danger },
  },
  compoundVariants: [
    { size: 'lg', intent: 'danger', class: styles.lgDanger },
  ],
  defaultVariants: { size: 'md', intent: 'primary' },
});

type ButtonProps = VariantProps<typeof button> & React.ButtonHTMLAttributes<HTMLButtonElement>;

export function Button({ size, intent, className, ...props }: ButtonProps) {
  return <button className={button({ size, intent, className })} {...props} />;
}

// app/layout.tsx — blocks paint until theme is resolved
const setTheme = `(function(){
  const t = localStorage.getItem('theme');
  const dark = matchMedia('(prefers-color-scheme: dark)').matches;
  document.documentElement.dataset.theme = t ?? (dark ? 'dark' : 'light');
})()`;

// Button.module.css
.button {
  background: var(--btn-bg, #0070f3);
  color: var(--btn-text, #fff);
  padding: 0.5rem 1rem;
  border-radius: 4px;
}

// Button.tsx
import styles from './Button.module.css';

type Props = { bg?: string; text?: string; label: string };

export function Button({ bg, text, label }: Props) {
  return (
    <button
      className={styles.button}
      style={{ '--btn-bg': bg, '--btn-text': text } as React.CSSProperties}
    >
      {label}
    </button>
  );
}

// Card.module.css
// .card { border-radius: 8px; transition: transform 200ms ease; }
// .cardLifted { composes: card; will-change: transform; }

import styles from './Card.module.css';
import { useState } from 'react';

export function Card({ children }: { children: React.ReactNode }) {
  const [lifted, setLifted] = useState(false);
  return (
    <div
      className={lifted ? styles.cardLifted : styles.card}
      onPointerDown={() => setLifted(true)}
      onAnimationEnd={() => setLifted(false)}
    >
      {children}
    </div>
  );
}

// postcss.config.js — custom extractor that handles CSS Modules object-property access
module.exports = {
  plugins: [
    require('@fullhuman/postcss-purgecss')({
      content: ['./src/**/*.{tsx,ts,jsx,js}'],
      defaultExtractor(content) {
        // Default extractor misses `styles.button` — capture property names too
        const broad = content.match(/[A-Za-z0-9_-]+/g) ?? [];
        const props = content.match(/(?<=\.)[A-Za-z0-9_]+/g) ?? [];
        return [...new Set([...broad, ...props])];
      },
    }),
  ],
};

